class Solution:
    def topKFrequent(self, words, k):
        counts = {}
        for w in words:
            counts[w] = counts.get(w, 0) + 1
        order = sorted(counts.keys())
        order.sort(key=lambda w: counts[w], reverse=True)
        return order[:k]

